INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('0fa1e44c-c397-4c1b-9559-233e0fad4716', 'You look like you describe beer the exact same way normal people describe a childhood trauma.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('c91ea0e1-c8dd-4b18-aa00-e801f3cbd9b2', 'Oh, you''re a ''founder''? Just say you''re unemployed and your parents pay your rent, it takes way less time.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('efb5e8e0-24d9-4639-8d70-7ce9b221d134', 'You have muscles on top of muscles, which is great, because it totally distracts from the fact that you have the personality of wet cardboard.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('0f3efcc7-4322-4a7b-af67-2dc282ee13ba', 'You''re 35 years old wearing Mickey Mouse ears. I don''t need to roast you; your credit score and dating history do that for me.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('18bdb841-aa2b-4c8e-9e69-987ddc2ca782', 'You look like you''ve roofied your own reflection just to see if it would work.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('195bb555-2203-4cd6-a888-2f35a233cfbb', 'No, Mercury isn''t in retrograde, you''re just a massive bitch.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('6658abcd-db4d-4272-9888-ae107a85679d', 'I''d roast you, but I don''t want to be the most interesting thing that happens on your next three-hour audio abortion.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('6318465a-6800-4be6-b6bc-e7aa06e781b1', 'You look like a guy who automated his own Tinder profile and still gets ghosted by bots.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('d2aab814-6b54-40a3-a7fc-4de032fd25be', 'You dress like a 1920s unicycle repairman who got lost on his way to a Brooklyn coffee shop.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('a8e81d53-2563-43b7-8d96-06f61fbea50b', 'Sorry you lost your Bored Ape. Maybe you should invest in a fucking shower.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('d734cef2-0454-44c9-828d-b101ebff3251', 'I can tell you''re vegan because you look like you''d snap in half if someone sneezed on you.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('f207c1f7-3e3f-4638-b3a0-2df86a457609', 'Blowing watermelon-scented smoke doesn''t make you look cool, it makes you look like a fruity dragon.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('23416985-4ef5-4939-927e-1e39ff5ad493', 'You spent two grand on a stationary bike just to get yelled at by a spinning instructor in your living room. Sounds like a very expensive humiliation fetish.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('b57e99cf-204d-4dd8-ac1b-8c402263daf4', 'Take the hat off, Indiana Jones. The only thing you''re exploring is the friend zone.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('f39df643-9cb9-407c-954e-bbb1417f142d', 'I''d ask you to shut the fuck up, but looking at you, nature has clearly already silenced your genetic line.', '[roast] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('eec11085-5967-458a-8728-aa2e7162147b', 'I finally deleted all my dating apps. I realized I was looking for love in all the wrong places. Now, I just wander around the local graveyard waiting for a rich widow to cry.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('603ca578-1fbe-46bf-9bc9-0a3f30a60dbc', 'Getting older is just a constant series of body betrayals. First your metabolism slows down, then your back goes out... and then one day you make a noise standing up from the couch that sounds exactly like a dying walrus.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('a6686d55-e666-49a2-ac8c-758fb50f944e', 'Whenever an automated voice says, ''Your call is very important to us''... I know for a fact I am about to spend 45 minutes listening to royalty-free jazz before a stranger hangs up on me.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('5bd8a9bb-00b7-47cb-9977-74b5a359ab4b', 'Inflation is getting so bad that I can''t even afford to have anxiety about it anymore. I went to buy a dozen eggs today and had to put down my car as collateral.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('24542848-2624-4c23-a869-eda485f6a90e', 'Everyone says you should go to therapy to fix your problems. I went for a year. Now I still have all the exact same problems, but I pay $200 an hour to complain about them using clinical vocabulary.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('22b5379c-699b-4552-b394-12457678f64f', 'When you''re 21, you can drink 15 shots of tequila, sleep in a bush, and wake up ready for a marathon. I''m in my 30s now. If I eat a piece of bread too fast at 8 PM, I need three days of bed rest.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('7deff4f9-fc0f-4b5e-9d1d-ea64e8abb2e8', 'I love looking at wedding registries. It''s so beautiful to see two people commit to spending the rest of their lives together... and demanding I buy them a $400 toaster just to witness it.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('e41e590b-6b66-4f2f-97a5-0fa9eaf303f0', 'I hate the self-checkout lane at the grocery store. I don''t work here. If I''m scanning my own items and bagging my own groceries, I expect a goddamn W-2 and dental benefits.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('dc516787-6314-461a-bc65-be34f85687e9', 'Sitting in rush hour traffic is a great way to catch up on podcasts. It’s also a great way to fully mentally prepare for driving your sedan off an overpass.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('2827f8a1-b19b-4548-9dbc-a669204c3558', 'I started intermittent fasting recently. It''s a great diet where you only eat during an eight-hour window. Unfortunately, during that window, I eat like a bear preparing for a brutal winter.', '[standup] Seed', 100, 0);
